const rows = $input.all().map(i => i.json);
if (!rows.length) {
  throw new Error('No passed candidate found for provided screening_id');
}
const payload = $('Normalize Payload').first().json;
const appBaseUrl = (payload.appBaseUrl || 'http://localhost:5173').replace(/\/$/, '');
const c = rows[0];
const link = `${appBaseUrl}/candidate-portal/assessment-instructions?id=${encodeURIComponent(c.screening_id)}`;
const html = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto; background: #ffffff;">
  <div style="background: linear-gradient(135deg, #1e40af, #3b82f6); padding: 32px 24px; text-align: center; border-radius: 8px 8px 0 0;">
    <h1 style="color: #ffffff; font-size: 24px; margin: 0;">CBC Inc.</h1>
    <p style="color: #bfdbfe; font-size: 13px; margin: 8px 0 0 0; letter-spacing: 1px;">AI-POWERED CANDIDATE SCREENING</p>
  </div>
  <div style="padding: 32px 24px; border: 1px solid #e5e7eb; border-top: none;">
    <h2 style="color: #1e293b; font-size: 20px; margin: 0 0 16px 0;">Technical Assessment Invitation</h2>
    <p style="color: #475569; font-size: 15px; line-height: 1.6;">Dear <strong>${c.name}</strong>,</p>
    <p style="color: #475569; font-size: 15px; line-height: 1.6;">You have passed pre-screening for the <strong>${c.role_title}</strong> role. You can now start your MCQ assessment.</p>
    <div style="text-align: center; margin: 28px 0;">
      <a href="${link}" style="background: #2563eb; color: #ffffff; padding: 14px 36px; text-decoration: none; border-radius: 8px; font-size: 16px; font-weight: 600; display: inline-block;">Start Assessment</a>
    </div>
    <p style="color: #94a3b8; font-size: 12px; text-align: center;">If the button doesn't work, copy and paste this link into your browser:<br/><a href="${link}" style="color: #3b82f6; word-break: break-all;">${link}</a></p>
  </div>
</div>`;
return [{ json: { to: c.email, subject: `Technical Assessment Invitation - ${c.role_title}`, html } }];
